const item = $input.first().json;

// ---------- helpers ----------
function safeParseJSON(x) {
  if (typeof x !== "string") return null;

  const cleaned = x
    .trim()
    .replace(/^```(?:json)?/i, "")
    .replace(/```$/i, "")
    .trim();

  try {
    return JSON.parse(cleaned);
  } catch (e) {
    return null;
  }
}

function isPlainObject(v) {
  return v !== null && typeof v === "object" && !Array.isArray(v);
}

function getFirstKeyByRegex(obj, regex) {
  if (!isPlainObject(obj)) return null;
  const keys = Object.keys(obj);
  for (let i = 0; i < keys.length; i++) {
    if (regex.test(keys[i])) return keys[i];
  }
  return null;
}

function pick(obj, keys, fallback) {
  for (let i = 0; i < keys.length; i++) {
    const k = keys[i];
    if (obj && obj[k] !== undefined && obj[k] !== null && String(obj[k]).trim() !== "") {
      return obj[k];
    }
  }
  return fallback || "";
}

// ---------- input normalize ----------
let data = item;

if (typeof item.output === "string") {
  const parsed = safeParseJSON(item.output);
  if (parsed) data = parsed;
}

if (typeof data === "string") {
  const parsed = safeParseJSON(data);
  if (parsed) data = parsed;
}

// ---------- get modules ----------
let modulesIn = [];

if (data && Array.isArray(data.modules)) {
  modulesIn = data.modules;
} else if (data && data.output && Array.isArray(data.output.modules)) {
  modulesIn = data.output.modules;
}

// ---------- transform ----------
const modulesOut = [];

for (let i = 0; i < modulesIn.length; i++) {
  const m = modulesIn[i];
  if (!isPlainObject(m)) continue;

  const moduleKey =
    getFirstKeyByRegex(m, /^module\s*\d+/i) ||
    getFirstKeyByRegex(m, /^title\s*\d+/i);

  const title = String(
    pick(m, [moduleKey, "module_title", "title"], "Module " + (i + 1))
  ).trim();

  const stepsIn = Array.isArray(m.steps) ? m.steps : [];
  const stepsOut = [];

  for (let j = 0; j < stepsIn.length; j++) {
    const s = stepsIn[j];
    if (!isPlainObject(s)) continue;

    const stepKey = getFirstKeyByRegex(s, /^step\s*\d+/i);

    stepsOut.push({
  step: "step " + (j + 1),
  step_title: String(s.step || s.step_title || "").trim(),
  Overview: s.Overview || s.overview || "",
  user_action: s.user_action || s.userAction || ""
});
  }

  modulesOut.push({
    title,
    steps: stepsOut
  });
}

return [
  {
    json: {
      modules: modulesOut
    }
  }
];

const items = $input.all();

if (!items || items.length === 0) {
  throw new Error("No input data received from Switch node");
}

const inputData = items[0].json || {};
console.log("Input data keys:", Object.keys(inputData));

// ---------- helpers ----------
function safeParseJSON(x) {
  if (typeof x !== "string") return null;

  const cleaned = x
    .trim()
    .replace(/^```(?:json)?/i, "")
    .replace(/```$/i, "")
    .trim();

  try {
    return JSON.parse(cleaned);
  } catch (e) {
    return null;
  }
}

function preview(v, n) {
  try {
    return JSON.stringify(v).substring(0, n || 200);
  } catch (e) {
    return String(v).substring(0, n || 200);
  }
}

// ---------- body normalize ----------
if (!inputData.body) {
  throw new Error("No 'body' field found in Switch output");
}

let body = inputData.body;

// If body is a string (common in webhook), parse it
if (typeof body === "string") {
  const parsedBody = safeParseJSON(body);
  if (parsedBody) body = parsedBody;
}

console.log("Body type:", typeof body);
console.log("Body keys:", body && typeof body === "object" ? Object.keys(body) : "body-not-object");

// ---------- extract domain/topic/modules ----------
let domain = "";
let topic = "";
let modules = null;

// parameters can also be a string
let params = body && body.parameters ? body.parameters : null;
if (typeof params === "string") {
  const parsedParams = safeParseJSON(params);
  if (parsedParams) params = parsedParams;
}

// domain/topic
if (params && typeof params === "object") {
  domain = params.domain || "";
  topic = params.topic || "";
}

// candidate modules sources (in priority order)
const candidates = [];

// 1) parameters.modules / parameters.output
if (params) {
  if (params.modules !== undefined) candidates.push(params.modules);
  if (params.output !== undefined) candidates.push(params.output);
}

// 2) body.modules / body.output
if (body && typeof body === "object") {
  if (body.modules !== undefined) candidates.push(body.modules);
  if (body.output !== undefined) candidates.push(body.output);
}

// 3) sometimes output is wrapped: { output: { modules: [...] } }
for (let i = 0; i < candidates.length; i++) {
  const c = candidates[i];

  // if string, try parse
  if (typeof c === "string") {
    const parsed = safeParseJSON(c);
    if (parsed) candidates[i] = parsed;
  }
}

// pick first candidate that yields modules array
for (let i = 0; i < candidates.length; i++) {
  const c = candidates[i];

  if (Array.isArray(c)) {
    modules = c;
    break;
  }

  if (c && typeof c === "object" && Array.isArray(c.modules)) {
    modules = c.modules;
    break;
  }

  // sometimes: { data: { modules: [...] } }
  if (c && typeof c === "object" && c.data && Array.isArray(c.data.modules)) {
    modules = c.data.modules;
    break;
  }
}

if (!modules) {
  const bodyKeys = body && typeof body === "object" ? Object.keys(body).join(", ") : "(body not object)";
  const paramKeys = params && typeof params === "object" ? Object.keys(params).join(", ") : "(no parameters)";
  throw new Error(
    "Cannot find modules array.\n" +
    "Body keys: " + bodyKeys + "\n" +
    "Parameters keys: " + paramKeys + "\n" +
    "Body preview: " + preview(body, 250)
  );
}

// validate modules
if (!Array.isArray(modules)) {
  throw new Error(
    "Modules is not an array. Type: " + typeof modules +
    ". Value preview: " + preview(modules, 250)
  );
}

if (modules.length === 0) {
  throw new Error("Modules array is empty");
}

// ---------- count total steps ----------
let totalSteps = 0;
for (let i = 0; i < modules.length; i++) {
  const mod = modules[i];
  if (mod && mod.steps && Array.isArray(mod.steps)) {
    totalSteps += mod.steps.length;
  }
}

console.log("Successfully extracted:", {
  domain: domain || "Not found",
  topic: topic || "Not found",
  moduleCount: modules.length,
  totalSteps: totalSteps
});

// ---------- output ----------
return [
  {
    json: {
      domain: domain || "Unknown Domain",
      topic: topic || "Unknown Topic",
      modules: modules,
      metadata: {
        total_modules: modules.length,
        total_steps: totalSteps,
        generated_at: new Date().toISOString()
      }
    }
  }
];

