const items = $input.all();

// Get domain and topic safely (avoid crash if missing)
const domain = items[0]?.json?.domain ?? "";
const topic = items[0]?.json?.topic ?? "";

// Clean + parse helper (fixes trailing commas and code fences)
function cleanJsonString(str) {
  return String(str)
    .replace(/```json/gi, "")
    .replace(/```/g, "")
    .trim()
    // Remove trailing commas before } or ]
    .replace(/,\s*(?=[}\]])/g, "");
}

const modules = [];

for (const item of items) {
  let aiOutput = item.json.output ?? item.json.text ?? item.json;

  // If it's a string, clean and parse to JSON
  if (typeof aiOutput === "string") {
    const cleaned = cleanJsonString(aiOutput);

    try {
      aiOutput = JSON.parse(cleaned);
    } catch (err) {
      // Skip bad module instead of crashing the whole workflow
      console.log("⚠️ Skipping invalid JSON module. Parse error:", err.message);
      console.log("---- Cleaned content start ----");
      console.log(cleaned);
      console.log("---- Cleaned content end ----");
      continue;
    }
  }

  // If parsed object is valid, push it
  if (aiOutput && typeof aiOutput === "object") {
    modules.push(aiOutput);
  }
}

// Return combined result
return [
  {
    json: {
      domain,
      topic,
      modules,
      metadata: {
        total_modules: modules.length,
        generated_at: new Date().toISOString(),
      },
    },
  },
];

