// ================================
// CLEAN DOCUMENT TEXT FORMATTER (n8n)
// ================================

// 1) Read AI header text safely
let aiText = $json.output?.[0]?.content?.[0]?.text || "";
aiText = String(aiText).replace(/\\n/g, "\n").trim();

// 2) Read modules from enrichment node (change node name if needed)
const modules = $node["Code in JavaScript1"]?.json?.modules || [];

// 3) Convert modules JSON into string
let modulesRaw = JSON.stringify(modules, null, 2);

// 4) Convert JSON-like text into readable document style
modulesRaw = String(modulesRaw)
  .replace(/\\n/g, "\n")       // unescape newlines
  .replace(/\\"/g, '"')        // unescape quotes
  .replace(/[{}\[\]]/g, "")    // remove brackets and braces
  .replace(/"/g, "")           // remove quotes
  .replace(/,\s*/g, "\n")      // commas -> new lines
  .replace(/\n\s*\n+/g, "\n")  // remove extra blank lines
  .trim();

// 5) Beautify indentation + structure
let modulesText = modulesRaw
  .split("\n")
  .map(line => line.trim())
  .filter(line => line.length > 0)
  .map(line => {
    // Add better layout rules
    if (/^module\s+\d+\s*:/.test(line)) return "\n" + line;               // blank line before module
    if (/^steps\s*:/.test(line)) return "  " + line;                      // indent steps
    if (/^step_name\s*:/.test(line)) return "    " + line;                // indent step
    if (/^Overview\s*:/.test(line)) return "      " + line;
    if (/^user_action\s*:/.test(line)) return "      " + line;
    if (/^tutorial_flow\s*:/.test(line)) return "      " + line;
    if (/^stage_\d+\s*:/.test(line)) return "        " + line;
    if (/^(vo1_aim|vo2_instruction|text_display|interaction_response)\s*:/.test(line))
      return "          " + line;
    if (/^stage_5_feedback\s*:/.test(line)) return "        " + line;
    if (/^vo3_conclusion\s*:/.test(line)) return "          " + line;

    return "      " + line; // default indent
  })
  .join("\n")
  .replace(/\n{3,}/g, "\n\n") // reduce huge gaps
  .trim();

// 6) Split OUTRO from header and keep it at end
// 6) Extract OUTRO properly and REMOVE from header
const outroRegex = /- OUTRO – VOICEOVER[\s\S]*/i;
let outroPart = "";
let headerPart = aiText;

const match = aiText.match(outroRegex);

if (match) {
  outroPart = match[0].trim();
  headerPart = aiText.replace(outroRegex, "").trim();
}

// 7) Final assembly (FORCE correct order)
const finalText = [
  headerPart,
  "",
  modulesText,
  "",
  outroPart
].filter(Boolean).join("\n\n").trim();
// 8) Return final clean document text
return [
  {
    json: {
      finalText
    }
  }
];
